svg.script:
document.addEventListener("DOMContentLoaded", () => {
    const addr = atob("Y29udGFjdEB0aG9sZWIuZnI=");
    const mailtag = document.getElementById("dsojqhbd");
    if (mailtag) {
        mailtag.textContent = addr; // Use textContent for SVG
    }
});

function openMail(e) {
    const addr = atob("Y29udGFjdEB0aG9sZWIuZnI=");
    window.location.href = "mailto:" + addr;
}
